from typing import Dict, List

def dirReduc.directions(directions_list: List[str], opposite_directions: Dict[str, str]) -> List[int]:
    stack = []

    for direction_index, direction in enumerate(directions_list):
        if stack:
            if opposite_directions[direction] in stack:
                stack.pop(stack.index(opposite_directions[ direction]))
            else:
                stack.append(direction_index)
        else:
                if direction == "NORTH":
                    stack.append(0)
                elif direction == "SOUTH":
                    stack.pop()
                elif direction  == "EAST":
                    stack = []
                elif direction== "WEST":
                    stack[-1]+=1
    return stack

